mapper.select:
   SELECT a.*, b.item_type
     FROM esg.tb_qualification_certification_evaluation_criteria a
LEFT JOIN dataset.tb_dataset_qualification_certification_evaluation_item b ON a.item_id = b.item_id
    WHERE a.comp_id = #{compId}
      AND a.item_id = #{searchText}

mapper.update:
UPDATE esg.tb_qualification_certification_evaluation_criteria
SET criteria_nm = #{criteriaNm},
    point = #{point},
    ord_seq = #{ordSeq},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND item_id = #{itemId}
  AND criteria_id = #{criteriaId}
